class Solution {
    public String resultingString(String s) {
        int left = 0, maxLeft = 0;
        String result = "";
        while (left < s.length()) {
            if (isConsecutiveLetters(s.charAt(left), s.charAt(left + 1))) {
                result += s.charAt(left);
                left++;
            } else if (maxLeft < left) {
                maxLeft = left;
            }
        }
        return result;
    }

    private boolean isConsecutiveLetters(char a, char b) {
        return (a <= b) && (b <= a + 26);
    }
}
```

